"""Trained 456-parameter transformer adder.

Trained from scratch: AdamW + reversed digits (LSB-first).
"""

import math

import torch
import torch.nn as nn
import torch.nn.functional as F


class RMSNormFree(nn.Module):
    def forward(self, x):
        return x * torch.rsqrt(x.pow(2).mean(-1, keepdim=True) + 1e-6)


def build_fixed_mask(max_seq=35):
    M = torch.full((3, max_seq, max_seq), float('-inf'))
    sep_score = 0.0
    for q in range(max_seq):
        if q < 21:
            for h in range(3):
                M[h, q, q] = 0.0
        else:
            k = q - 21
            if k < 10:
                M[0, q, k] = 0.0
                M[0, q, 11 + k] = 0.0
            M[0, q, 10] = sep_score
            if k == 0:
                M[1, q, 10] = sep_score
            else:
                for j in range(min(k, 10)):
                    score = -(k - j) * math.log(10)
                    M[1, q, j] = score
                    M[1, q, 11 + j] = score
            M[2, q, q] = 0.0
    return M


class TrainableAdder(nn.Module):
    def __init__(self):
        super().__init__()
        self.d = 6
        self.n_heads = 3
        self.d_head = 2
        self.embed = nn.Embedding(12, 6)
        self.q_proj = nn.Linear(6, 6, bias=False)
        self.k_proj = nn.Linear(6, 6, bias=False)
        self.v_proj = nn.Linear(6, 6, bias=False)
        self.o_proj = nn.Linear(6, 6, bias=False)
        self.mlp_up = nn.Linear(6, 12, bias=True)
        self.mlp_down = nn.Linear(12, 6, bias=False)
        self.norm1 = RMSNormFree()
        self.norm2 = RMSNormFree()
        self.norm_f = RMSNormFree()
        self.lm_head = nn.Linear(6, 12, bias=True)
        self.register_buffer('fixed_mask', build_fixed_mask())

    def forward(self, x):
        B, L = x.shape
        h = self.embed(x)
        hn = self.norm1(h)
        q = self.q_proj(hn).view(B, L, 3, 2).transpose(1, 2)
        k = self.k_proj(hn).view(B, L, 3, 2).transpose(1, 2)
        v = self.v_proj(hn).view(B, L, 3, 2).transpose(1, 2)
        scores = (q @ k.transpose(-2, -1)) / math.sqrt(2.0)
        scores = scores + self.fixed_mask[:, :L, :L].unsqueeze(0)
        attn_out = (F.softmax(scores, dim=-1) @ v).transpose(1, 2).reshape(B, L, 6)
        h = h + self.o_proj(attn_out)
        hn2 = self.norm2(h)
        h = h + self.mlp_down(F.relu(self.mlp_up(hn2)))
        h_norm = self.norm_f(h)
        return self.lm_head(h_norm)


