def build_model():
    model = TrainableAdder()
    model.load_state_dict(WEIGHTS, strict=False)
    model.eval()
    metadata = {
        "name": "456-Parameter Trained Adder",
        "author": "fblissjr",
        "params": 456,
        "architecture": "1L d=6 3h ff=12 reversed-digits",
        "tricks": ['Reversed LSB-First', 'Teacher Forcing', 'RMSNorm', 'Fixed Mask (hand-coded routing)'],
    }
    return model, metadata


def add(model, a: int, b: int) -> int:
    sa = f"{a:010d}"[::-1]
    sb = f"{b:010d}"[::-1]
    seq = [int(c) for c in sa] + [10] + [int(c) for c in sb] + [11]
    device = next(model.parameters()).device
    model.eval()
    with torch.no_grad():
        for _ in range(11):
            x = torch.tensor([seq], dtype=torch.long, device=device)
            logits = model(x)
            seq.append(logits[0, -1].argmax().item())
    c_digits = seq[22:33]
    return sum(d * (10**i) for i, d in enumerate(c_digits))
